Re-split `sanitized` before the second length check, or combine the two passes:
```ts
export function sanitizeDecimalInput(value: string): string {
  const stripped = value.replace(/[^\d.]/g, '');
  const dotIndex = stripped.indexOf('.');
  if (dotIndex === -1) return stripped;
  const integer = stripped.slice(0, dotIndex);
  const decimal = stripped.slice(dotIndex + 1).replace(/\./g, '').slice(0, 1);
  return `${integer}.${decimal}`;
}
```

